  ('elementary-0a2fc18c-moex-00745', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '生產可能性曲線（productionpossibilitiescurve）主要是介紹：', '["一個經濟體應該生產的產品數量的集合", "一個經濟體應該消費的產品數量的集合", "一個經濟體可以生產的產品數量的集合", "一個經濟體可以消費的產品數量的集合"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "9ca9da4c9d41", "answer_pdf_sha1": "8f8f31d133df", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
