  ('elementary-0a2fc18c-moex-00748', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '市場由供給與需求決定均衡價格與數量時，下列敘述何者正確？', '["無謂損失最大", "社會福利最大", "生產者剩餘最小", "消費者剩餘等於零"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "9ca9da4c9d41", "answer_pdf_sha1": "8f8f31d133df", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
